import scala.collection.mutable.PriorityQueue

def solve(m: Long, n: Long, waitCost: Array[Array[Long]]): Long = {
   val rows = m.toInt
   val cols = n.toInt
   val dist = Array.ofDim[Long](rows, cols, 2)
   for (i <- 0 until rows) {
      for (j <- 0 until cols) {
         dist(i)(j)(0) = Long.MaxValue
         dist(i)(j)(1) = Long.MaxValue
      }
   }
   dist(0)(0)(1) = 1L
   val pq = PriorityQueue[(Long, Int, Int, Int)]()
   pq += (1L, 0, 0, 1)
   while (pq.nonEmpty) {
      val (cost, i, j, parity) = pq.pop()
      if (i == rows - 1 && j == cols - 1) return cost
      if (cost > dist(i)(j)(parity)) {
         // Skip processing if a better path has already been found
         continue
      }
      if (parity == 0) {
         val newCost = cost + waitCost(i)(j)
         if (newCost < dist(i)(j)(1)) {
            dist(i)(j)(1) = newCost
            pq += (newCost, i, j, 1)
         }
      } else {
         val moves = List[(Int, Int)](
            (i + 1, j),
            (i, j + 1)
         ).filter { case (ni, nj) => ni < rows && nj < cols }
         for ((ni, nj) <- moves) {
            val entrance = (ni + 1) * (nj + 1)
            val newCost = cost + entrance
            if (newCost < dist(ni)(nj)(0)) {
               dist(ni)(nj)(0) = newCost
               pq += (newCost, ni, nj, 0)
            }
         }
      }
   }
   Long.MaxValue
}
